    <style>  
        /* Container cho nút điện thoại */  
        .floating-contact {  
            position: fixed;  
            bottom: 30px;  
            left: 70px;  
            z-index: 9999;  
            display: flex;  
            flex-direction: column;  
            align-items: flex-start;
			gap: 15px;
        }  

        /* Style cho nút điện thoại */  
        .phone-btn {  
            display: flex;  
            align-items: center;  
            background-color: #c50000;  
            color: white;  
            padding: 8px 15px;  
            border-radius: 25px;  
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);  
            cursor: pointer;  
            transition: all 0.3s ease;  
        }  

        .phone-btn:hover {  
            transform: scale(1.05);  
            background-color: #e60000;  
        }  

        .phone-icon {  
            width: 24px;  
            height: 24px;  
            background-color: white;  
            border-radius: 50%;  
            display: flex;  
            justify-content: center;  
            align-items: center;  
            margin-right: 10px;  
        }  
        
        .phone-icon svg {  
            fill: #c50000;  
        }  

        .phone-number {  
            font-weight: bold;  
            font-size: 16px;  
        }  

        /* Hiệu ứng pulse cho nút điện thoại */  
        .pulse {  
            animation: pulse 1.5s infinite;  
            border-radius: 25px;  
            position: absolute;  
            top: 0;  
            left: 0;  
            width: 100%;  
            height: 100%;  
            background-color: rgba(255, 255, 255, 0.4);  
            z-index: -1;  
        }  
		.message-btn {
		  display: inline-block;
		  animation: scaleUp 3s ease-in-out infinite; /* Thêm animation tự động */
		}

		@keyframes scaleUp {
		  0% {
			transform: scale(0.8);
		  }
		  50% {
			transform: scale(1.1);
		  }
		  100% {
			transform: scale(1);
		  }
		}
		
        @keyframes pulse {  
            0% {  
                transform: scale(1);  
                opacity: 0.5;  
            }  
            70% {  
                transform: scale(1.1);  
                opacity: 0;  
            }  
            100% {  
                transform: scale(1);  
                opacity: 0;  
            }  
        }  

        /* Ẩn nút trên thiết bị mobile */  
        @media (max-width: 768px) {  
            .floating-contact {  
                display: none;  
            }  
        }
		@media screen and (min-width: 1024px) {
			.pkcp-parent-container {
				left: 70px !important;
				bottom: 200px !important;
			}
			.pkcp-button-wrapper-welcome__container {
				left: 0px !important;
			}
			.pkcp-popup.pkcp-popup-open {
				bottom: -110px !important;
			}
		}
		.wd-product .product-wrapper {
			height: 100% !important;
		}
		.wd-entities-title {
			max-height: max-content !important;
		}
    </style> 
